.html-card {
  width: 100%;
  height: 100%;
  padding: 24px;
  border: 1px solid rgba(255, 255, 255, 0.24);
  border-radius: 12px;
  background: rgba(15, 23, 42, 0.72);
  color: #ffffff;
  font-family: Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}

.html-card h3 {
  margin: 0 0 12px;
  font-size: 24px;
  font-weight: 600;
  line-height: 1.3;
}

.html-card p {
  margin: 0;
  font-size: 14px;
  line-height: 1.6;
}
